    const event = this.#makeEvent(projectId, null, { initiator: "workspace_create", sessionId: null, actorId, component: null, commandId: request.command_id, commandDigest, eventType: "project.created", refs: [{ kind: "actor", id: actorId, digest: actorDigest }], next: base, response, status: 201, now });
