      const payload = command.payload;
      exactKeys(payload as unknown as Record<string, unknown>, ["operation", "parent_decision_brief_revision_id", "question", "decision_owner", "objective", "constraints", "assumptions", "non_goals", "sources"]);
      if (payload.operation === "create") { if (payload.parent_decision_brief_revision_id !== null || snapshot.current.decision_brief_revision_id !== null) throw new ApiError(409, "revision_not_current", "A brief already exists."); }
